const BUS_URL = 'https://n8n.vanlaar.cloud/webhook/bus-schedule-next?dir=volos&remaining=0&dayOffset=0';
const MIN_ITEMS = 1;

let payload = null;
let fetchError = null;

try {
  payload = await this.helpers.httpRequest({
    method: 'GET',
    url: BUS_URL,
    json: true,
    timeout: 30000,
  });
} catch (e) {
  fetchError = e?.message || String(e);
}

const meta = payload?.meta || {};
const items = Array.isArray(payload?.items) ? payload.items : [];
const tz = meta.tz || null;
const generatedAt = meta.generatedAt || null;
const query = meta.query || {};
const ymd = meta.now?.ymd || null;

const issues = [];
if (fetchError) issues.push(`Bus webhook fetch mislukt: ${fetchError}`);
if (!fetchError && tz !== 'Europe/Athens') issues.push(`meta.tz verwacht Europe/Athens, ontving: ${tz}`);
if (!fetchError && items.length < MIN_ITEMS) {
  issues.push(`Geen bus-items voor vandaag (dir=volos, dayOffset=0): ${items.length} rijen`);
}
if (!fetchError && !meta.now) issues.push('meta.now ontbreekt in bus-response');

const ok = issues.length === 0;
const subject = ok
  ? '[kalanera] Bus sanity OK'
  : '[kalanera] ALERT: bus-schedule-next probleem';

const sampleTimes = items.slice(0, 5).map((r) => r.Time_KalaNera || r.time || '?').join(', ');

const lines = [
  'Kalanera — dagelijkse bus sanity check',
  `Tijd (UTC): ${new Date().toISOString()}`,
  `URL: ${BUS_URL}`,
  '',
  `Athens datum (meta.now.ymd): ${ymd || '(onbekend)'}`,
  `meta.tz: ${tz || '(onbekend)'}`,
  `Items vandaag (volos): ${items.length}`,
  generatedAt ? `generatedAt: ${generatedAt}` : '',
  sampleTimes ? `Eerste tijden: ${sampleTimes}` : '',
  '',
];

if (ok) {
  lines.push('Status: OK — bus-widget heeft data voor vandaag.');
} else {
  lines.push('Status: PROBLEEM');
  lines.push('');
  issues.forEach((msg) => lines.push(`- ${msg}`));
  lines.push('');
  lines.push('Actie: controleer Bus_Schedule Sheet, bus-schedule-next workflow en n8n executions.');
}

function escHtml(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function toBodyHtml(lines) {
  return `<!DOCTYPE html><html><body style="font-family:system-ui,sans-serif;font-size:14px;line-height:1.45;max-width:42em"><pre style="white-space:pre-wrap;margin:0">${escHtml(lines.filter(Boolean).join('\n'))}</pre></body></html>`;
}
const body = lines.filter(Boolean).join('\n');

return [{
  json: {
    ok,
    alert: !ok,
    itemCount: items.length,
    tz,
    ymd,
    generatedAt,
    query,
    issues,
    subject,
    body,
    bodyHtml: toBodyHtml(lines),
  },
}];
